let current = 0;
let score = 0;
let correctCount = 0;
let wrongCount = 0;
let answered = false;
let shuffled = [];

function startQuiz() {
  shuffled = [...questions].sort(() => Math.random() - 0.5);
  current = 0;
  score = 0;
  correctCount = 0;
  wrongCount = 0;
  answered = false;
  document.getElementById('home').style.display = 'none';
  document.getElementById('quiz').classList.remove('hidden');
  loadQuestion();
}




function loadQuestion() {
  if (current >= shuffled.length) {
    showResult();
    return;
  }

  const q = shuffled[current];
  document.getElementById('question').textContent = q.text;

  const hintBtn = document.getElementById('hintBtn');
  const hintText = document.getElementById('hintText');
  hintText.textContent = q.hint || "কোনো হিন্ট নেই";
  hintText.style.display = 'none';
  hintBtn.style.display = 'inline-block';
  hintBtn.onclick = () => {
    hintText.style.display = 'block';
    hintBtn.style.display = 'none';
  };

  document.getElementById('explanation').style.display = 'none';

  const optsDiv = document.getElementById('options');
  optsDiv.innerHTML = '';

  q.options.forEach((opt, i) => {
    const div = document.createElement('div');
    div.className = 'option';
    div.textContent = opt;
    div.onclick = () => selectAnswer(i, q);
    optsDiv.appendChild(div);
  });

  document.getElementById('resultBtn').style.display = current > 0 ? 'inline-block' : 'none';
  document.getElementById('nextBtn').disabled = true;
  answered = false;
  updateProgress();
}




function selectAnswer(idx, q) {
  if (answered) return;
  answered = true;

  const opts = document.querySelectorAll('.option');
  opts[q.correct].classList.add('correct');

  const clicked = opts[idx];
  clicked.classList.add('selected');

  if (idx === q.correct) {
    score += 100;
    correctCount++;
  } else {
    clicked.classList.add('wrong');
    score -= 0.5;
    wrongCount++;

    const exp = document.getElementById('explanation');
    exp.textContent = q.explanation || "সঠিক উত্তর: " + q.options[q.correct];
    exp.style.display = 'block';
  }

  document.getElementById('nextBtn').disabled = false;
}

function nextQuestion() {
  current++;
  loadQuestion();
}

function updateProgress() {
  const pct = ((current + 1) / shuffled.length) * 100;
  document.getElementById('progress').style.width = pct + '%';
  
  document.getElementById('progressCount').textContent = (current + 1) + " / " + shuffled.length;
}

function showResult() {
  document.getElementById('quiz').classList.add('hidden');
  document.getElementById('result').classList.remove('hidden');

  const percentage = Math.round((score / (shuffled.length * 100)) * 100);
  document.getElementById('finalScore').textContent = percentage + "%";
  document.getElementById('correctCount').textContent = correctCount;
  document.getElementById('wrongCount').textContent = wrongCount;
}

function restart() {
  document.getElementById('result').classList.add('hidden');
  startQuiz();

}
